    uint32_t M = static_cast<uint32_t>(a_shape->GetOriginShape().GetDim(1));
    uint32_t N = static_cast<uint32_t>(b_shape->GetOriginShape().GetDim(1));

    gert::Shape *c_shape = context->GetOutputShape(0);
